function maxNumEdgesToRemove(n, edges) {
    let parent = new Array(2 * n + 1).fill().map((_, i) => i);

    function find(u) {
        return parent[u] === u ? u : parent[u] = find(parent[u]);
    }

    function unite(u, v) {
        u = find(u);
        v = find(v);
        if (u !== v) {
            parent[u] = v;
            return true;
        }
        return false;
    }

    edges.sort((a, b) => b[0] - a[0]);
    let ct = [0, 0];
    let both = n - 1;
    for (let edge of edges) {
        if (edge[0] === 3 && unite(edge[1], edge[2] + n)) {
            both--;
        }
        if (both === 0) break;
    }

    for (let type = 1; type < 3; type++) {
        for (let edge of edges) {
            if (edge[0] === type && unite(edge[1], edge[2] + n)) {
                ct[type - 1]++;
            }
        }
        if (both + ct[type - 1] < n - 1) {
            return -1;
        }
    }

    return ct[0] + ct[1] - n + 1;
}
```


    1. Initialize the parent array for the union-find data structure for each node, twice the size of n (to handle both Alice and Bob).
2. Define find and unite functions for the union-find data structure.
3. Sort the edges in descending order based on their type.
4. Iterate through the edges, and only process type 3 (common) edges.
5. During the iteration, attempt to unite the current edge nodes. If successful, decrement the remaining edges to be fully traversed (both variable).
6. Once both variable becomes 0, break from the loop.
7. For each type (Alice or Bob):
   * Iterate through the edges
   * If the edge type matches the current type and the edge can be united, increment the count for the current type.
   * If the total count of edges for fully traversal by Alice and Bob is less than the required number, return -1 as it is impossible.
8. Finally, return the total count of removed edges.

